/*! Gado Game Engine v1.0 | Advanced JS Game Engine for Web */
const Gado = (function() {
    class GadoEngine {
        constructor(config = {}) {
            this.canvas = document.getElementById(config.canvas) || document.createElement('canvas');
            if (!this.canvas.parentNode) document.body.appendChild(this.canvas);
            
            this.ctx = this.canvas.getContext('2d');
            this.width = config.width || 800;
            this.height = config.height || 600;
            this.canvas.width = this.width;
            this.canvas.height = this.height;
            
            this.background = config.background || '#0a0a2e';
            this.sprites = [];
            this.keys = {};
            this.score = 0;
            this.gameRunning = false;
            this.lastTime = 0;
            
            this.setupControls();
        }
        
        setupControls() {
            window.addEventListener('keydown', e => this.keys[e.key] = true);
            window.addEventListener('keyup', e => this.keys[e.key] = false);
            
            this.canvas.addEventListener('click', (e) => {
                if (typeof this.onClick === 'function') this.onClick(e);
            });
        }
        
        addSprite(options) {
            const sprite = {
                x: options.x || 100,
                y: options.y || 100,
                width: options.width || 50,
                height: options.height || 50,
                color: options.color || '#ff6b35',
                speed: options.speed || 5,
                vx: 0,
                vy: 0,
                ...options
            };
            this.sprites.push(sprite);
            return sprite;
        }
        
        onKeyDown(key, callback) {
            this.keyCallbacks = this.keyCallbacks || {};
            this.keyCallbacks[key] = callback;
        }
        
        start(loopCallback) {
            this.gameRunning = true;
            this.loop = (timestamp) => {
                if (!this.gameRunning) return;
                this.ctx.fillStyle = this.background;
                this.ctx.fillRect(0, 0, this.width, this.height);
                
                this.sprites.forEach(sprite => {
                    sprite.x += sprite.vx || 0;
                    sprite.y += sprite.vy || 0;
                    
                    this.ctx.fillStyle = sprite.color;
                    this.ctx.fillRect(sprite.x, sprite.y, sprite.width, sprite.height);
                    
                    if (sprite.draw) sprite.draw(this.ctx);
                });
                
                if (typeof loopCallback === 'function') loopCallback();
                
                requestAnimationFrame(this.loop);
            };
            requestAnimationFrame(this.loop);
        }
        
        stop() {
            this.gameRunning = false;
        }
        
        detectCollision(a, b) {
            return !(a.x + a.width < b.x || 
                     b.x + b.width < a.x || 
                     a.y + a.height < b.y || 
                     b.y + b.height < a.y);
        }
    }
    
    return GadoEngine;
})();

// Global export
window.Gado = Gado;
console.log('%c🎮 Gado Game Engine loaded successfully! v1.0', 'color: #ff6b35; font-size: 14px;');